// kaya wire vocabulary. Generated by kaya-bindgen from kaya::spec — do not edit.
//
// Records are {u32 size, u16 kind, u16 flags}, body, padded to 8,
// little-endian. Values accept Go bool, int64, float64, and string,
// mapped to the kaya value types; keys in paths likewise.
package kaya

import (
	"encoding/binary"
	"math"
)

const (
	ValueBool = 1
	ValueI64 = 2
	ValueF64 = 3
	ValueStr = 4
	KindColumn = 1
	KindButton = 2
	KindLabel = 3
	KindEntry = 4
	KindRow = 5
	KindCheckbox = 6
	PropText = 1
	PropChecked = 2
	SourceConst = 0
	SourceSignal = 1
	SourceElement = 2
	OccurrencePad = 0
	OccurrenceButtonClicked = 1
	OccurrenceTextChanged = 2
	OccurrenceToggled = 3
	txCreateSignal = 1
	txWriteSignal = 2
	txCreateWidget = 3
	txSetProperty = 4
	txAddChild = 5
	txMount = 6
	txCreateCollection = 7
	txCollectionInsert = 8
	txCollectionUpdate = 9
	txCollectionRemove = 10
	txCreateFor = 11
	txCreateWhen = 12
	txTemplateEnd = 13
	txCollectionUpdateField = 14
	applyCreate = 1
	applySetProp = 2
	applyAddChild = 3
	applyMount = 4
	applyDestroy = 5
	occButtonClicked = 1
	occTextChanged = 2
	occToggled = 3
)

func pad8(b []byte) []byte {
	for len(b)%8 != 0 {
		b = append(b, 0)
	}
	return b
}

// encodeValue appends one kaya value; values self-pad to 8 because
// they concatenate inside record bodies.
func encodeValue(b []byte, v any) []byte {
	switch x := v.(type) {
	case bool:
		b = binary.LittleEndian.AppendUint32(b, ValueBool)
		b = binary.LittleEndian.AppendUint32(b, 1)
		if x {
			b = append(b, 1)
		} else {
			b = append(b, 0)
		}
	case int:
		return encodeValue(b, int64(x))
	case int64:
		b = binary.LittleEndian.AppendUint32(b, ValueI64)
		b = binary.LittleEndian.AppendUint32(b, 8)
		b = binary.LittleEndian.AppendUint64(b, uint64(x))
	case float64:
		b = binary.LittleEndian.AppendUint32(b, ValueF64)
		b = binary.LittleEndian.AppendUint32(b, 8)
		b = binary.LittleEndian.AppendUint64(b, math.Float64bits(x))
	case string:
		b = binary.LittleEndian.AppendUint32(b, ValueStr)
		b = binary.LittleEndian.AppendUint32(b, uint32(len(x)))
		b = append(b, x...)
	default:
		panic("kaya: value must be bool, int64, float64, or string")
	}
	return pad8(b)
}

// encodeValues appends a counted value sequence — a key path or a
// record: {u32 count, u32 reserved, count values}.
func encodeValues(b []byte, vals []any) []byte {
	b = binary.LittleEndian.AppendUint32(b, uint32(len(vals)))
	b = binary.LittleEndian.AppendUint32(b, 0)
	for _, v := range vals {
		b = encodeValue(b, v)
	}
	return b
}

// encodeTypeTags appends a collection schema: {u32 count, u32 reserved,
// count Value* tags}, padded to 8.
func encodeTypeTags(b []byte, tags []uint32) []byte {
	b = binary.LittleEndian.AppendUint32(b, uint32(len(tags)))
	b = binary.LittleEndian.AppendUint32(b, 0)
	for _, t := range tags {
		b = binary.LittleEndian.AppendUint32(b, t)
	}
	for len(b)%8 != 0 {
		b = append(b, 0)
	}
	return b
}

func beginRecord(kind uint16) []byte {
	b := make([]byte, 0, 64)
	b = append(b, 0, 0, 0, 0)
	b = binary.LittleEndian.AppendUint16(b, kind)
	return append(b, 0, 0)
}

func endRecord(b []byte) []byte {
	b = pad8(b)
	binary.LittleEndian.PutUint32(b, uint32(len(b)))
	return b
}

// TxCreateSignal: Create a signal holding `initial`.
func TxCreateSignal(signalId uint64, initial any) []byte {
	b := beginRecord(txCreateSignal)
	b = binary.LittleEndian.AppendUint64(b, signalId)
	b = encodeValue(b, initial)
	return endRecord(b)
}

// TxWriteSignal: Replace a signal's value; keep-latest per batch.
func TxWriteSignal(signalId uint64, value any) []byte {
	b := beginRecord(txWriteSignal)
	b = binary.LittleEndian.AppendUint64(b, signalId)
	b = encodeValue(b, value)
	return endRecord(b)
}

// TxCreateWidget: Create a live widget, or declare a template node inside a scope.
func TxCreateWidget(widgetId uint64, kind uint32) []byte {
	b := beginRecord(txCreateWidget)
	b = binary.LittleEndian.AppendUint64(b, widgetId)
	b = binary.LittleEndian.AppendUint32(b, kind)
	b = binary.LittleEndian.AppendUint32(b, 0)
	return endRecord(b)
}

// TxAddChild: Append `child` to `parent` (same zone only).
func TxAddChild(parent uint64, child uint64) []byte {
	b := beginRecord(txAddChild)
	b = binary.LittleEndian.AppendUint64(b, parent)
	b = binary.LittleEndian.AppendUint64(b, child)
	return endRecord(b)
}

// TxMount: Mount a root into a window (0 = the default window).
func TxMount(window uint64, root uint64) []byte {
	b := beginRecord(txMount)
	b = binary.LittleEndian.AppendUint64(b, window)
	b = binary.LittleEndian.AppendUint64(b, root)
	return endRecord(b)
}

// TxCreateCollection: Declare a collection and its schema — the ordered field types every entry must match; a scalar collection is the one-field case. A blueprint when inside a template.
func TxCreateCollection(collectionId uint64, schema []uint32) []byte {
	b := beginRecord(txCreateCollection)
	b = binary.LittleEndian.AppendUint64(b, collectionId)
	b = encodeTypeTags(b, schema)
	return endRecord(b)
}

// TxCollectionInsert: Insert an entry into the instance at `path`; the fields match the schema positionally. Stamps a copy.
func TxCollectionInsert(collectionId uint64, path []any, key any, fields []any) []byte {
	b := beginRecord(txCollectionInsert)
	b = binary.LittleEndian.AppendUint64(b, collectionId)
	b = encodeValues(b, path)
	b = encodeValue(b, key)
	b = encodeValues(b, fields)
	return endRecord(b)
}

// TxCollectionUpdate: Replace an entry's record; every element binding follows.
